// التبديل بين الأقسام
function switchSection(sectionId, element) {
    // إخفاء كل الأقسام
    document.querySelectorAll('.main-section').forEach(sec => sec.classList.remove('active'));
    // إلغاء تفعيل روابط القائمة
    document.querySelectorAll('.nav-link').forEach(link => link.classList.remove('active'));

    // إظهار القسم المطلوب وتفعيل رابطه
    document.getElementById(sectionId).classList.add('active');
    element.classList.add('active');
}

// بناء قائمة السور
function initQuran() {
    const listContainer = document.getElementById('surahListContainer');
    listContainer.innerHTML = '';

    for (let id in quranData) {
        const surah = quranData[id];
        const div = document.createElement('div');
        div.className = 'surah-item' + (id == 1 ? ' active' : '');
        div.onclick = function () {
            document.querySelectorAll('.surah-item').forEach(item => item.classList.remove('active'));
            div.classList.add('active');
            loadSurah(id);
        };

        div.innerHTML = `
                    <span style="display:flex; align-items:center; gap:10px;">
                        <span class="surah-number">${id}</span>
                        <span>سورة ${surah.name}</span>
                    </span>
                    <span style="font-size:12px; color:#777;">${surah.type}</span>
                `;
        listContainer.appendChild(div);
    }

    // تحميل سورة الفاتحة كبداية
    loadSurah(1);
}

// عرض السورة المختارة
function loadSurah(id) {
    const surah = quranData[id];
    document.getElementById('currentSurahTitle').innerText = 'سورة ' + surah.name;

    const textContainer = document.getElementById('quranTextContainer');
    let fullText = '';

    surah.verses.forEach((verse, index) => {
        fullText += verse + ` <span class="aya-number">﴿${index + 1}﴾</span> `;
    });

    textContainer.innerHTML = fullText;
}

// تحميل الأحاديث
function initHadiths() {
    const container = document.getElementById('hadithContainer');
    container.innerHTML = '';

    hadiths.forEach(h => {
        const card = document.createElement('div');
        card.className = 'hadith-card';
        card.innerHTML = `
                    <div class="hadith-title">${h.title}</div>
                    <div class="hadith-text">" ${h.text} "</div>
                    <div class="hadith-rawi">${h.rawi}</div>
                `;
        container.appendChild(card);
    });
}

// نظام السبحة الإلكترونية
let count = 0;
function incrementCounter() {
    count++;
    document.getElementById('counterValue').innerText = count;
}

function resetCounter() {
    count = 0;
    document.getElementById('counterValue').innerText = count;
}

// تشغيل الدوال عند تحميل الصفحة
window.onload = function () {
    initQuran();
    initHadiths();
};